 30→function filterSections(sections: SectionData[], query: string): SectionData[] {
 31→  if (!query) return sections;
 32→  const lower = query.toLowerCase();
 33→  return sections
 34→    .map(section => ({
 35→      ...section,
 36→      items: section.items.filter(
 37→        item =>
 38→          item.title.toLowerCase().includes(lower) ||
 39→          item.subtitle?.toLowerCase().includes(lower),
 40→      ),
 41→    }))
 42→    .filter(section => section.items.length > 0);
 43→}
 44→
 45→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 46→  if (!query) return colors;
 47→  const lower = query.toLowerCase();
 48→  return colors.filter(
 49→    c =>
 50→      c.title.toLowerCase().includes(lower) ||
 51→      c.subtitle?.toLowerCase().includes(lower),
 52→  );
 53→}
 54→
 55→function flattenItems(sections: SectionData[]): ListItemData[] {
 56→  return sections.flatMap(s => s.items);
 57→}
 58→
 59→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 60→  switch (entry.type) {
 61→    case 'label':
 62→      return (
 63→        <DetailMetadata.Label
 64→          key={index}
 65→          title={entry.title}
 66→          text={entry.text}
 67→        />
 68→      );
 69→    case 'link':
 70→      return (
 71→        <DetailMetadata.Link
 72→          key={index}
 73→          title={entry.title}
 74→          text={entry.text}
 75→          target={entry.target}
 76→        />
 77→      );
 78→    case 'tag-list':
 79→      return (
 80→        <DetailMetadata.TagList key={index} title={entry.title}>
 81→          {entry.tags.map(tag => (
 82→            <DetailMetadata.Tag
 83→              key={tag.text}
 84→              text={tag.text}
 85→              color={tag.color}
 86→            />
 87→          ))}
 88→        </DetailMetadata.TagList>
 89→      );
 90→    case 'separator':
 91→      return <DetailMetadata.Separator key={index} />;
 92→  }
 93→}
 94→
 95→function ColorSwatch({ color }: { color: string }) {
 96→  return (
 97→    <div
 98→      className="grid-item__color-swatch"
 99→      style={{ backgroundColor: color }}
100→    />
101→  );
102→}
