129→interface SnippetFormState {
130→  name: string;
131→  keyword: string;
132→  snippet: string;
133→  category: string;
134→  isShared: boolean;
135→  expiresAt: string;
136→}
137→
138→const INITIAL_SNIPPET_FORM: SnippetFormState = {
139→  name: '',
140→  keyword: '',
141→  snippet: '',
142→  category: 'general',
143→  isShared: false,
144→  expiresAt: '',
145→};
