147→const SNIPPET_CATEGORIES = [
148→  {
149→    label: 'General',
150→    value: 'general',
151→  },
152→  {
153→    label: 'Code',
154→    value: 'code',
155→  },
156→  {
157→    label: 'Email',
158→    value: 'email',
159→  },
160→  {
161→    label: 'Template',
162→    value: 'template',
163→  },
