  1→import { type KeyboardEvent, Fragment, useEffect, useRef } from 'react';
  2→import './search_bar.scss';
  3→
  4→export interface BreadcrumbItem {
  5→  label: string;
  6→  onBack?: () => void;
  7→}
  8→
  9→interface SearchBarProps {
 10→  value: string;
 11→  onChange: (value: string) => void;
 12→  placeholder?: string;
 13→  activeDescendantId?: string;
 14→  breadcrumbs?: BreadcrumbItem[];
 15→}
 16→
 17→export function SearchBar({
 18→  value,
 19→  onChange,
 20→  placeholder = 'Search...',
 21→  activeDescendantId,
 22→  breadcrumbs,
 23→}: SearchBarProps) {
 24→  const inputRef = useRef<HTMLInputElement>(null);
 25→
 26→  useEffect(() => {
 27→    inputRef.current?.focus();
 28→  }, []);
 29→
 30→  function handleInputKeyDown(e: KeyboardEvent<HTMLInputElement>) {
 31→    if (e.key !== 'Escape' || !breadcrumbs || breadcrumbs.length === 0) {
 32→      return;
 33→    }
 34→
 35→    e.preventDefault();
 36→    if (value) {
 37→      onChange('');
 38→      return;
 39→    }
 40→
 41→    for (let i = breadcrumbs.length - 1; i >= 0; i--) {
 42→      const crumb = breadcrumbs[i];
 43→      if (crumb?.onBack) {
 44→        crumb.onBack();
 45→        return;
 46→      }
 47→    }
 48→  }
 49→
 50→  return (
 51→    <div className="search-bar" role="search">
 52→      <svg
 53→        className="search-bar__icon"
 54→        width="16"
 55→        height="16"
 56→        viewBox="0 0 16 16"
 57→        fill="none"
 58→        xmlns="http://www.w3.org/2000/svg"
 59→      >
 60→        <circle cx="7" cy="7" r="4.5" stroke="currentColor" strokeWidth="1.5" />
 61→        <line
 62→          x1="10.5"
 63→          y1="10.5"
 64→          x2="14"
 65→          y2="14"
 66→          stroke="currentColor"
 67→          strokeWidth="1.5"
 68→          strokeLinecap="round"
 69→        />
 70→      </svg>
 71→      {breadcrumbs && breadcrumbs.length > 0 && (
 72→        <nav className="search-bar__breadcrumbs" aria-label="Breadcrumb">
 73→          {breadcrumbs.map((crumb, i) => {
 74→            const isLast = i === breadcrumbs.length - 1;
 75→            return (
 76→              <Fragment key={i}>
 77→                {i > 0 && (
 78→                  <svg
 79→                    className="search-bar__breadcrumb-chevron"
 80→                    width="8"
 81→                    height="8"
 82→                    viewBox="0 0 8 8"
 83→                    fill="none"
 84→                    aria-hidden="true"
 85→                  >
 86→                    <path
 87→                      d="M2.5 1.5L5.5 4L2.5 6.5"
 88→                      stroke="currentColor"
 89→                      strokeWidth="1.2"
 90→                      strokeLinecap="round"
 91→                      strokeLinejoin="round"
 92→                    />
 93→                  </svg>
 94→                )}
 95→                {isLast ? (
 96→                  <span
 97→                    className="search-bar__breadcrumb search-bar__breadcrumb--current"
 98→                    aria-current="location"
 99→                  >
100→                    {crumb.label}
101→                  </span>
102→                ) : (
103→                  <button
104→                    className="search-bar__breadcrumb"
105→                    onClick={crumb.onBack}
106→                    type="button"
107→                    aria-label={`Back to ${crumb.label}`}
108→                  >
109→                    {crumb.label}
110→                  </button>
111→                )}
112→              </Fragment>
113→            );
114→          })}
115→        </nav>
116→      )}
117→      <input
118→        ref={inputRef}
119→        className="search-bar__input"
120→        type="text"
121→        value={value}
122→        onChange={e => onChange(e.target.value)}
123→        onKeyDown={handleInputKeyDown}
124→        placeholder={placeholder}
125→        role="combobox"
126→        aria-expanded={true}
127→        aria-controls="command-list"
128→        aria-activedescendant={activeDescendantId}
129→        aria-label="Search commands"
130→        spellCheck={false}
131→        autoComplete="off"
132→      />
133→    </div>
134→  );
135→}
