 3→import { type ReactNode, useMemo } from 'react';
 4→import './detail.scss';
 5→
 6→export interface DetailProps {
 7→  markdown: string;
 8→  metadata?: ReactNode;
 9→}
10→
11→export function Detail({ markdown, metadata }: DetailProps) {
12→  const renderedHtml = useMemo(
13→    () => DOMPurify.sanitize(marked.parse(markdown, { async: false })),
14→    [markdown],
15→  );
16→
17→  return (
18→    <div
19→      className={`detail${metadata ? ' detail--with-metadata' : ''}`}
20→      role="region"
21→      aria-label="Detail view"
22→    >
23→      <div className="detail__content" role="document">
24→        <div
25→          className="detail__markdown"
26→          dangerouslySetInnerHTML={{ __html: renderedHtml }}
27→        />
28→      </div>
29→      {metadata && <div className="detail__metadata">{metadata}</div>}
30→    </div>
31→  );
32→}
